import { lazy } from 'react';

// project imports
import Loadable from 'components/Loadable';
import DashboardLayout from 'layout/Dashboard';

// Các trang (Pages)
const DashboardDefault = Loadable(lazy(() => import('pages/dashboard/default')));
const ProductsPage = Loadable(lazy(() => import('pages/products'))); // <- Khai báo file vừa tạo

// ==============================|| MAIN ROUTING ||============================== //

const MainRoutes = {
  path: '/',
  element: <DashboardLayout />,
  children: [
    {
      path: '/',
      element: <DashboardDefault />
    },
    {
      path: 'dashboard',
      children: [
        {
          path: 'default',
          element: <DashboardDefault />
        }
      ]
    },
    {
      path: 'products',
      element: <ProductsPage /> // <- Khai báo đường dẫn kết nối vào Menu
    }
  ]
};

export default MainRoutes;